"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const points=['A1 / intake','B4 / verify','C2 / group','D3 / ready'];
export default function CoordinateScanLoader(){const [step,setStep]=useState(0);const reduced=useReducedMotion();const done=step===points.length;const advance=()=>setStep(done?0:step+1);return <section aria-label="Coordinate scan loader" className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><p className="text-xs font-bold uppercase tracking-[.14em] text-[#4a4a4f]">coordinate scan</p><div className="relative mt-4 space-y-2"><motion.i aria-hidden animate={{y:Math.min(step,3)*42}} transition={reduced?{duration:.12}:{type:'spring',stiffness:300,damping:25}} className="absolute left-0 top-3 block h-6 w-1 rounded-full bg-[#0d9488]"/>{points.map((point,index)=><div key={point} className="flex min-h-9 items-center rounded-xl border border-[#ececee] pl-4 text-sm font-bold text-[#111]"><span className="mr-2 text-[#4a4a4f]">{index<step?'✓':index===step&&!done?'•':'○'}</span>{point}</div>)}</div><motion.button type="button" onClick={advance} whileHover={reduced?undefined:{y:-2}} whileTap={reduced?undefined:{y:1}} className="mt-4 min-h-11 w-full rounded-xl bg-[#111] px-3 text-sm font-bold text-white outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">{done?'Restart scan':'Next checkpoint'}</motion.button><p aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">{done?'All coordinates indexed.':`Checkpoint ${step+1} of ${points.length}.`}</p></section>}
